import React from 'react';
import { User } from 'lucide-react';

export default function ProfileScreen({ userName }) {
  return (
    <div className="pb-24 animate-fade-in">
      <header className="px-6 pt-12 pb-6 flex items-center bg-white sticky top-0 z-10">
        <User className="w-6 h-6 text-gray-600 mr-2" />
        <h1 className="text-2xl font-bold text-gray-800">Profile</h1>
      </header>

      <div className="px-6 mt-6 space-y-4">
        <div className="bg-white p-6 rounded-2xl shadow border border-gray-50">
          <p className="text-gray-500 text-sm">Name</p>
          <h2 className="font-bold text-gray-800 text-lg">{userName}</h2>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow border border-gray-50">
          <p className="text-gray-500 text-sm">Settings</p>
          <p className="text-gray-400 text-sm mt-1">Profile settings, security options, logout...</p>
        </div>
      </div>
    </div>
  );
}
